// Formatear la respuesta del OCR de Mistral
const ocrResult = $input.first();

// Verificar si hay datos
if (!ocrResult) {
  return {
    success: false,
    error: 'No data received from Mistral OCR node',
    raw_response: ''
  };
}

// Extraer el texto del resultado
let extractedText = '';
let confidence = 0;
let pageCount = 0;

if (ocrResult.json && ocrResult.json.text) {
  extractedText = ocrResult.json.text;
  confidence = ocrResult.json.confidence || 0;
  pageCount = ocrResult.json.pages?.length || 1;
} else if (ocrResult.json && ocrResult.json.choices && ocrResult.json.choices[0]) {
  extractedText = ocrResult.json.choices[0].message?.content || '';
} else if (typeof ocrResult.json === 'string') {
  extractedText = ocrResult.json;
} else if (ocrResult.json) {
  extractedText = JSON.stringify(ocrResult.json, null, 2);
}

// Estadísticas del texto
const wordCount = extractedText.split(/\s+/).filter(word => word.length > 0).length;
const charCount = extractedText.length;
const lineCount = extractedText.split('\n').length;

// Detectar idioma (simple detección)
const spanishWords = ['el', 'la', 'de', 'que', 'y', 'en', 'un', 'es', 'se', 'no', 'te', 'lo', 'le', 'da', 'su', 'por', 'son', 'con', 'para', 'al', 'del', 'los', 'las'];
const englishWords = ['the', 'be', 'to', 'of', 'and', 'a', 'in', 'that', 'have', 'i', 'it', 'for', 'not', 'on', 'with', 'he', 'as', 'you', 'do', 'at'];

const words = extractedText.toLowerCase().split(/\s+/);
const spanishCount = words.filter(word => spanishWords.includes(word)).length;
const englishCount = words.filter(word => englishWords.includes(word)).length;

const detectedLanguage = spanishCount > englishCount ? 'Spanish' : 'English';

// Crear respuesta estructurada
const response = {
  success: true,
  timestamp: new Date().toISOString(),
  document_info: {
    type: 'Image (processed)',
    pages: pageCount,
    language: detectedLanguage,
    confidence: confidence
  },
  text_analysis: {
    character_count: charCount,
    word_count: wordCount,
    line_count: lineCount,
    has_content: charCount > 0
  },
  extracted_text: extractedText,
  processing_info: {
    model_used: 'mistral-ocr-latest',
    processed_at: new Date().toISOString(),
    processing_time: 'N/A'
  }
};

return response;

// Manejar errores del OCR
const errorData = $input.first();

const errorResponse = {
  success: false,
  timestamp: new Date().toISOString(),
  error: {
    message: errorData.error?.message || 'OCR processing failed',
    type: 'OCR_ERROR',
    details: errorData.error || 'Unknown error occurred during OCR processing'
  },
  document_info: {
    type: 'Image (processed)',
    status: 'Failed'
  },
  suggestions: [
    'Ensure the document/image is clear and readable',
    'Check if the file format is supported',
    'Try with a different document if the issue persists'
  ]
};

return errorResponse;
